-- curriculum-seed-3d.sql — Phase 3.4 NERDC curriculum alignment
-- Run in the Neon SQL Editor (HTTPS/443). MTN broadband blocks port 5432,
-- so this is applied by hand, NOT by the installer.
--
-- Table: curriculum_topics  (Prisma model CurriculumTopic, @@map)
-- Columns are camelCase and therefore QUOTED in raw SQL.
-- Unique key: (subject, "className", term, week) -> ON CONFLICT DO NOTHING
-- makes this script safe to re-run.
--
-- All rows seeded with source='DRAFT'. After spot-check, relabel per-subject:
--   UPDATE curriculum_topics SET source='NERDC' WHERE subject='Mathematics' AND source='DRAFT';
--
-- Total rows: 252

ON CONFLICT ("subject","className","term","week") DO NOTHING;

